import{_ as e,o as a,c as l,ag as d}from"./chunks/framework.DTiDeF2Q.js";const g=JSON.parse('{"title":"Funciones | Dotfiles (ES)","titleTemplate":":title","description":"Funciones de shell que mejoran tu experiencia en el terminal. Utilidades para API, archivos y operaciones del sistema.","frontmatter":{"title":"Funciones | Dotfiles","description":"Funciones de shell que mejoran tu experiencia en el terminal. Utilidades para API, archivos y operaciones del sistema.","lang":"es-ES","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Funciones preview","canonical":"/es/functions/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Funciones","pageType":"docs","schemaType":"WebPage","metaTitle":"Funciones - Dotfiles (ES)","permalink":"/es/functions/","meta":[{"name":"keywords","content":"funciones, shell, bash, zsh, dotfiles, productividad, utilidades, api, archivos, sistema"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"Funciones de shell que mejoran tu experiencia en el terminal. Utilidades para API, archivos y operaciones del sistema."},{"name":"twitter:title","content":"Funciones - Dotfiles"},{"name":"og:title","content":"Funciones - Dotfiles"},{"name":"og:description","content":"Funciones de shell que mejoran tu experiencia en el terminal. Utilidades para API, archivos y operaciones del sistema."},{"name":"og:image:alt","content":"Dotfiles - Diseñado para tu vida en el shell"},{"name":"og:locale","content":"es_ES"}]},"headers":[],"relativePath":"es/functions/index.md","filePath":"es/functions/index.md","lastUpdated":1773010926000}'),i={name:"es/functions/index.md"};function o(s,t,n,r,c,f){return a(),l("div",null,[...t[0]||(t[0]=[d('<h1 id="funciones" tabindex="-1">Funciones <a class="header-anchor" href="#funciones" aria-label="Permalink to &quot;Funciones&quot;">​</a></h1><p>Utilidades de shell para aumentar tu productividad en macOS, Linux y Windows.</p><h2 id="descubrir" tabindex="-1">Descubrir <a class="header-anchor" href="#descubrir" aria-label="Permalink to &quot;Descubrir&quot;">​</a></h2><p>Las funciones se definen en archivos <code>.sh</code> individuales. Durante <code>chezmoi apply</code>, se agregan en <code>~/.config/shell/functions.sh</code> y se cargan en tu shell.</p><h2 id="empezar" tabindex="-1">Empezar <a class="header-anchor" href="#empezar" aria-label="Permalink to &quot;Empezar&quot;">​</a></h2><h3 id="anadir-una-funcion" tabindex="-1">Añadir una función <a class="header-anchor" href="#anadir-una-funcion" aria-label="Permalink to &quot;Añadir una función&quot;">​</a></h3><ol><li>Crea un nuevo archivo <code>.sh</code> (por ejemplo <code>mifuncion.sh</code>)</li><li>Añade la definición de tu función</li><li>Aplica los cambios:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chezmoi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apply</span></span></code></pre></div></li></ol><h2 id="referencia" tabindex="-1">Referencia <a class="header-anchor" href="#referencia" aria-label="Permalink to &quot;Referencia&quot;">​</a></h2><h3 id="pruebas-de-api" tabindex="-1">Pruebas de API <a class="header-anchor" href="#pruebas-de-api" aria-label="Permalink to &quot;Pruebas de API&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Función</th><th style="text-align:left;">Descripción</th><th style="text-align:left;">Uso</th></tr></thead><tbody><tr><td style="text-align:left;"><code>apihealth</code></td><td style="text-align:left;">Comprobar la salud de una o varias APIs</td><td style="text-align:left;"><code>apihealth [OPTIONS] URL [URL ...]</code></td></tr><tr><td style="text-align:left;"><code>apilatency</code></td><td style="text-align:left;">Medir la latencia de una API</td><td style="text-align:left;"><code>apilatency URL [COUNT] [INTERVAL]</code></td></tr><tr><td style="text-align:left;"><code>apiload</code></td><td style="text-align:left;">Ejecutar una prueba de carga básica</td><td style="text-align:left;"><code>apiload URL [REQUESTS] [DELAY]</code></td></tr><tr><td style="text-align:left;"><code>httpdebug</code></td><td style="text-align:left;">Depurar peticiones HTTP con tiempos</td><td style="text-align:left;"><code>httpdebug [options] [url]</code></td></tr></tbody></table><h3 id="utilidades-http" tabindex="-1">Utilidades HTTP <a class="header-anchor" href="#utilidades-http" aria-label="Permalink to &quot;Utilidades HTTP&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Función</th><th style="text-align:left;">Descripción</th><th style="text-align:left;">Uso</th></tr></thead><tbody><tr><td style="text-align:left;"><code>curlheader</code></td><td style="text-align:left;">Ver cabeceras HTTP</td><td style="text-align:left;"><code>curlheader [header] [url]</code></td></tr><tr><td style="text-align:left;"><code>curlstatus</code></td><td style="text-align:left;">Comprobar el código de estado HTTP</td><td style="text-align:left;"><code>curlstatus [url]</code></td></tr><tr><td style="text-align:left;"><code>curltime</code></td><td style="text-align:left;">Medir métricas de tiempo HTTP</td><td style="text-align:left;"><code>curltime [url]</code></td></tr><tr><td style="text-align:left;"><code>view-source</code></td><td style="text-align:left;">Ver el código fuente de un sitio</td><td style="text-align:left;"><code>view-source URL</code></td></tr><tr><td style="text-align:left;"><code>whoisport</code></td><td style="text-align:left;">Encontrar el proceso que usa un puerto</td><td style="text-align:left;"><code>whoisport PORT</code></td></tr></tbody></table><h3 id="gestion-de-archivos" tabindex="-1">Gestión de archivos <a class="header-anchor" href="#gestion-de-archivos" aria-label="Permalink to &quot;Gestión de archivos&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Función</th><th style="text-align:left;">Descripción</th><th style="text-align:left;">Uso</th></tr></thead><tbody><tr><td style="text-align:left;"><code>backup</code></td><td style="text-align:left;">Crear copias de seguridad con timestamp</td><td style="text-align:left;"><code>backup [--max-size SIZE] [--keep N] &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>encode64</code> / <code>decode64</code></td><td style="text-align:left;">Codificación/decodificación Base64</td><td style="text-align:left;"><code>encode64 &quot;string&quot;</code></td></tr><tr><td style="text-align:left;"><code>extract</code></td><td style="text-align:left;">Extraer formatos de archivo</td><td style="text-align:left;"><code>extract [file]</code></td></tr><tr><td style="text-align:left;"><code>hexdump</code></td><td style="text-align:left;">Mostrar un archivo en formato hex</td><td style="text-align:left;"><code>hexdump [file] [lines]</code></td></tr><tr><td style="text-align:left;"><code>ren</code></td><td style="text-align:left;">Renombrar extensiones por lotes</td><td style="text-align:left;"><code>ren OLD_EXT NEW_EXT</code></td></tr><tr><td style="text-align:left;"><code>size</code></td><td style="text-align:left;">Comprobar tamaño de archivo o directorio</td><td style="text-align:left;"><code>size [file/directory]</code></td></tr><tr><td style="text-align:left;"><code>zipf</code></td><td style="text-align:left;">Crear archivos ZIP</td><td style="text-align:left;"><code>zipf [folder]</code></td></tr></tbody></table><h3 id="nombres-de-archivo" tabindex="-1">Nombres de archivo <a class="header-anchor" href="#nombres-de-archivo" aria-label="Permalink to &quot;Nombres de archivo&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Función</th><th style="text-align:left;">Descripción</th><th style="text-align:left;">Uso</th></tr></thead><tbody><tr><td style="text-align:left;"><code>kebabcase</code></td><td style="text-align:left;">Convertir a kebab-case</td><td style="text-align:left;"><code>kebabcase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>lowercase</code></td><td style="text-align:left;">Convertir a minúsculas</td><td style="text-align:left;"><code>lowercase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>sentencecase</code></td><td style="text-align:left;">Convertir a mayúscula de frase</td><td style="text-align:left;"><code>sentencecase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>snakecase</code></td><td style="text-align:left;">Convertir a snake_case</td><td style="text-align:left;"><code>snakecase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>titlecase</code></td><td style="text-align:left;">Convertir a Title Case</td><td style="text-align:left;"><code>titlecase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>uppercase</code></td><td style="text-align:left;">Convertir a MAYÚSCULAS</td><td style="text-align:left;"><code>uppercase &lt;files...&gt;</code></td></tr></tbody></table><h3 id="utilidades-del-sistema" tabindex="-1">Utilidades del sistema <a class="header-anchor" href="#utilidades-del-sistema" aria-label="Permalink to &quot;Utilidades del sistema&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Función</th><th style="text-align:left;">Descripción</th><th style="text-align:left;">Uso</th></tr></thead><tbody><tr><td style="text-align:left;"><code>caffeine</code></td><td style="text-align:left;">Evitar que el sistema duerma</td><td style="text-align:left;"><code>caffeine [command]</code></td></tr><tr><td style="text-align:left;"><code>environment</code></td><td style="text-align:left;">Detectar el entorno del SO</td><td style="text-align:left;"><code>environment</code></td></tr><tr><td style="text-align:left;"><code>freespace</code></td><td style="text-align:left;">Limpiar espacio purgable</td><td style="text-align:left;"><code>freespace [disk]</code></td></tr><tr><td style="text-align:left;"><code>hiddenfiles</code></td><td style="text-align:left;">Mostrar/ocultar archivos ocultos en Finder</td><td style="text-align:left;">`hiddenfiles [show</td></tr><tr><td style="text-align:left;"><code>hostinfo</code></td><td style="text-align:left;">Mostrar información del host</td><td style="text-align:left;"><code>hostinfo</code></td></tr><tr><td style="text-align:left;"><code>hstats</code></td><td style="text-align:left;">Ver estadísticas de uso de comandos</td><td style="text-align:left;"><code>hstats</code></td></tr><tr><td style="text-align:left;"><code>last</code></td><td style="text-align:left;">Listar archivos modificados recientemente</td><td style="text-align:left;"><code>last [minutes]</code></td></tr><tr><td style="text-align:left;"><code>logout</code></td><td style="text-align:left;">Cerrar sesión multiplataforma</td><td style="text-align:left;"><code>logout [--force]</code></td></tr><tr><td style="text-align:left;"><code>myproc</code></td><td style="text-align:left;">Listar procesos del usuario</td><td style="text-align:left;"><code>myproc</code></td></tr><tr><td style="text-align:left;"><code>stopwatch</code></td><td style="text-align:left;">Cronómetro en terminal</td><td style="text-align:left;"><code>stopwatch</code></td></tr><tr><td style="text-align:left;"><code>sysinfo</code></td><td style="text-align:left;">Mostrar información del sistema</td><td style="text-align:left;"><code>sysinfo</code></td></tr></tbody></table><h3 id="comandos-caffeine" tabindex="-1">Comandos Caffeine <a class="header-anchor" href="#comandos-caffeine" aria-label="Permalink to &quot;Comandos Caffeine&quot;">​</a></h3><p>Evita que el sistema se duerma o active el salvapantallas.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Comando</th><th style="text-align:left;">Descripción</th></tr></thead><tbody><tr><td style="text-align:left;"><code>caffeine daemon</code></td><td style="text-align:left;">Iniciar el daemon caffeine</td></tr><tr><td style="text-align:left;"><code>caffeine status</code></td><td style="text-align:left;">Ver si el daemon está activo</td></tr><tr><td style="text-align:left;"><code>caffeine start</code></td><td style="text-align:left;">Mantener la pantalla despierta</td></tr><tr><td style="text-align:left;"><code>caffeine stop</code></td><td style="text-align:left;">Permitir que la pantalla duerma</td></tr><tr><td style="text-align:left;"><code>caffeine toggle</code></td><td style="text-align:left;">Alternar pantalla despierta</td></tr><tr><td style="text-align:left;"><code>caffeine shutdown</code></td><td style="text-align:left;">Detener el daemon</td></tr></tbody></table><p>Funciona en macOS (<code>caffeinate</code>), Linux (<code>xdg-screensaver</code>) y Windows (PowerShell).</p><h3 id="seguridad" tabindex="-1">Seguridad <a class="header-anchor" href="#seguridad" aria-label="Permalink to &quot;Seguridad&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Función</th><th style="text-align:left;">Descripción</th><th style="text-align:left;">Uso</th></tr></thead><tbody><tr><td style="text-align:left;"><code>genpass</code></td><td style="text-align:left;">Generar contraseñas seguras</td><td style="text-align:left;"><code>genpass [num_blocks] [separator]</code></td></tr><tr><td style="text-align:left;"><code>keygen</code></td><td style="text-align:left;">Generar pares de claves SSH</td><td style="text-align:left;"><code>keygen [name] [email] [type] [bits]</code></td></tr></tbody></table><h3 id="navegacion" tabindex="-1">Navegación <a class="header-anchor" href="#navegacion" aria-label="Permalink to &quot;Navegación&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Función</th><th style="text-align:left;">Descripción</th><th style="text-align:left;">Uso</th></tr></thead><tbody><tr><td style="text-align:left;"><code>cdls</code></td><td style="text-align:left;">Cambiar de directorio y listar</td><td style="text-align:left;"><code>cdls [directory]</code></td></tr><tr><td style="text-align:left;"><code>goto</code></td><td style="text-align:left;">Navegación rápida de directorios</td><td style="text-align:left;"><code>goto [directory]</code></td></tr><tr><td style="text-align:left;"><code>mount_read_only</code></td><td style="text-align:left;">Montar de solo lectura como lectura/escritura</td><td style="text-align:left;"><code>mount_read_only [image]</code></td></tr><tr><td style="text-align:left;"><code>rd</code></td><td style="text-align:left;">Eliminar un directorio</td><td style="text-align:left;"><code>rd [directory]</code></td></tr><tr><td style="text-align:left;"><code>remove_disk</code></td><td style="text-align:left;">Expulsar un disco de forma segura</td><td style="text-align:left;"><code>remove_disk [disk]</code></td></tr></tbody></table><h3 id="miscelanea" tabindex="-1">Miscelánea <a class="header-anchor" href="#miscelanea" aria-label="Permalink to &quot;Miscelánea&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Función</th><th style="text-align:left;">Descripción</th><th style="text-align:left;">Uso</th></tr></thead><tbody><tr><td style="text-align:left;"><code>matrix</code></td><td style="text-align:left;">Efectos Matrix en terminal</td><td style="text-align:left;"><code>matrix [options]</code></td></tr><tr><td style="text-align:left;"><code>prependpath</code></td><td style="text-align:left;">Añadir un directorio al PATH</td><td style="text-align:left;"><code>prependpath [directory]</code></td></tr><tr><td style="text-align:left;"><code>ql</code></td><td style="text-align:left;">Abrir en Quick Look (macOS)</td><td style="text-align:left;"><code>ql [file]</code></td></tr><tr><td style="text-align:left;"><code>vscode</code></td><td style="text-align:left;">Abrir en VS Code</td><td style="text-align:left;"><code>vscode [file]</code></td></tr></tbody></table><h2 id="compatibilidad" tabindex="-1">Compatibilidad <a class="header-anchor" href="#compatibilidad" aria-label="Permalink to &quot;Compatibilidad&quot;">​</a></h2><ul><li><strong>macOS</strong> — Soporte completo con utilidades específicas</li><li><strong>Linux</strong> — Compatible con distribuciones comunes</li><li><strong>Windows</strong> — Soporte vía WSL, Cygwin o Git Bash</li></ul><h2 id="ayuda" tabindex="-1">Ayuda <a class="header-anchor" href="#ayuda" aria-label="Permalink to &quot;Ayuda&quot;">​</a></h2><p>Cada función incluye ayuda con <code>--help</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apihealth</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --help</span></span></code></pre></div>',33)])])}const y=e(i,[["render",o]]);export{g as __pageData,y as default};
